command:
mkdir -p .homeycompose
cat << 'EOF' > .homeycompose/app.json
{
  "id": "net.magnus.lightcontroller",
  "version": "1.0.0",
  "sdk": 3,
  "compatibility": ">=12.0.1",
  "name": {
    "en": "Light Controller"
  },
  "description": {
    "en": "Controller for Homey lights."
  },
  "category": "tools",
  "author": {
    "name": "Magnus"
  }
}
EOF

cat << 'EOF' > app.ts
import Homey from 'homey';

export default class MyApp extends Homey.App {
  async onInit() {
    this.log('MyApp has been initialized');
  }
}
EOF

cat << 'EOF' > api.js
export default {};
EOF

node -e '
const fs = require("fs");
const pkg = JSON.parse(fs.readFileSync("package.json"));
pkg.scripts.test = "vitest run";
fs.writeFileSync("package.json", JSON.stringify(pkg, null, 2));
'

